        p += wh * Wosize_hd(hd);
      } else {
        /* there's still a live block, the pool can't be released to the global
            freelist */
        release_to_global_pool = 0;
      }
      p += Whsize_hd(hd);
    } while (p + wh <= end);
    CAMLassert(p == end);

    if( !all_used ) {
      /* the last free block should have 0 as its next pointer */
      last_free_block[1] = 0;
    }

    CAMLassert(
      /* if all spaces are used then next_obj should be 0 */
